"use client";

// ============================================================
// PART 1 ??Imports & Types
// ============================================================

import { useState, useCallback, useRef } from "react";
import { Database, Play, Clock, Table2, Settings, Loader2, AlertTriangle, ChevronRight, ChevronDown } from "lucide-react";

export interface DBConnection {
  id: string;
  name: string;
  type: "sqlite" | "postgresql" | "mysql" | "mongodb";
  connectionString: string;
  connected: boolean;
}

export interface QueryResult {
  columns: string[];
  rows: Record<string, unknown>[];
  rowCount: number;
  executionTime: number;
  error?: string;
}

interface QueryHistoryEntry {
  id: string;
  query: string;
  timestamp: number;
  success: boolean;
}

interface DatabasePanelProps {
  connections: DBConnection[];
  onConnect: (conn: DBConnection) => Promise<boolean>;
  onExecuteQuery: (connectionId: string, query: string) => Promise<QueryResult>;
  tables?: string[];
}

// IDENTITY_SEAL: PART-1 | role=Types | inputs=none | outputs=DBConnection,QueryResult

// ============================================================
// PART 2 ??Sidebar (Tables & History)
// ============================================================

function TableList({
  tables,
  onSelect,
}: {
  tables: string[];
  onSelect: (table: string) => void;
}) {
  const [expanded, setExpanded] = useState(true);
  return (
    <div className="border-b border-white/5">
      <button
        onClick={() => setExpanded(!expanded)}
        className="flex w-full items-center gap-1 px-2 py-1.5 text-xs font-bold uppercase tracking-wider text-gray-500 hover:text-gray-300"
      >
        {expanded ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
        Tables ({tables.length})
      </button>
      {expanded && (
        <div className="pb-1">
          {tables.map((t) => (
            <button
              key={t}
              onClick={() => onSelect(t)}
              className="flex w-full items-center gap-1.5 px-3 py-1 text-xs text-gray-400 hover:bg-white/5 hover:text-white"
            >
              <Table2 size={12} className="text-blue-400" />
              {t}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

function HistoryList({
  history,
  onSelect,
}: {
  history: QueryHistoryEntry[];
  onSelect: (query: string) => void;
}) {
  const [expanded, setExpanded] = useState(false);
  return (
    <div>
      <button
        onClick={() => setExpanded(!expanded)}
        className="flex w-full items-center gap-1 px-2 py-1.5 text-xs font-bold uppercase tracking-wider text-gray-500 hover:text-gray-300"
      >
        {expanded ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
        History ({history.length})
      </button>
      {expanded && (
        <div className="max-h-40 overflow-y-auto pb-1">
          {history.map((h) => (
            <button
              key={h.id}
              onClick={() => onSelect(h.query)}
              className={`flex w-full items-start gap-1.5 px-3 py-1 text-xs hover:bg-white/5 ${
                h.success ? "text-gray-400" : "text-red-400"
              }`}
            >
              <Clock size={10} className="mt-0.5 shrink-0" />
              <span className="truncate">{h.query}</span>
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

// IDENTITY_SEAL: PART-2 | role=Sidebar | inputs=tables,history | outputs=JSX

// ============================================================
// PART 3 ??Results Table
// ============================================================

function ResultsTable({ result }: { result: QueryResult | null }) {
  if (!result) {
    return (
      <div className="flex h-full items-center justify-center text-sm text-gray-500">
        Run a query to see results
      </div>
    );
  }
  if (result.error) {
    return (
      <div className="flex items-center gap-2 p-4 text-sm text-red-400">
        <AlertTriangle size={14} />
        {result.error}
      </div>
    );
  }
  return (
    <div className="h-full overflow-auto">
      <table className="w-full border-collapse text-xs">
        <thead className="sticky top-0 bg-[#1e1e2e]">
          <tr>
            {result.columns.map((col) => (
              <th key={col} className="border-b border-white/10 px-3 py-1.5 text-left font-medium text-gray-400">
                {col}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {result.rows.map((row, ri) => (
            <tr key={ri} className="hover:bg-white/5">
              {result.columns.map((col) => (
                <td key={col} className="border-b border-white/5 px-3 py-1 text-gray-300">
                  {String(row[col] ?? "NULL")}
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
      <div className="border-t border-white/5 px-3 py-1 text-[10px] text-gray-500">
        {result.rowCount} rows returned in {result.executionTime}ms
      </div>
    </div>
  );
}

// IDENTITY_SEAL: PART-3 | role=ResultsTable | inputs=QueryResult | outputs=JSX

// ============================================================
// PART 4 ??Main Panel
// ============================================================

export default function DatabasePanel({
  connections,
  onConnect,
  onExecuteQuery,
  tables = [],
}: DatabasePanelProps) {
  const [activeConn, setActiveConn] = useState<string>(connections[0]?.id ?? "");
  const [query, setQuery] = useState("SELECT * FROM ");
  const [result, setResult] = useState<QueryResult | null>(null);
  const [running, setRunning] = useState(false);
  const [history, setHistory] = useState<QueryHistoryEntry[]>([]);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const execute = useCallback(async () => {
    if (!activeConn || !query.trim()) return;
    setRunning(true);
    try {
      const res = await onExecuteQuery(activeConn, query);
      setResult(res);
      setHistory((h) => [
        { id: `q-${Date.now()}`, query: query.trim(), timestamp: Date.now(), success: !res.error },
        ...h.slice(0, 49),
      ]);
    } catch (err) {
      setResult({ columns: [], rows: [], rowCount: 0, executionTime: 0, error: String(err) });
    } finally {
      setRunning(false);
    }
  }, [activeConn, query, onExecuteQuery]);

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if ((e.ctrlKey || e.metaKey) && e.key === "Enter") {
      e.preventDefault();
      execute();
    }
  };

  return (
    <div className="flex h-full">
      {/* Sidebar */}
      <div className="w-48 shrink-0 border-r border-white/5 overflow-y-auto bg-[#16161e]">
        <div className="border-b border-white/5 px-2 py-2">
          <select
            value={activeConn}
            onChange={(e) => setActiveConn(e.target.value)}
            className="w-full rounded bg-white/5 px-2 py-1 text-xs text-white border border-white/10 outline-none"
          >
            {connections.map((c) => (
              <option key={c.id} value={c.id}>{c.name}</option>
            ))}
          </select>
        </div>
        <TableList tables={tables} onSelect={(t) => setQuery(`SELECT * FROM ${t} LIMIT 100;`)} />
        <HistoryList history={history} onSelect={setQuery} />
      </div>

      {/* Main area */}
      <div className="flex flex-1 flex-col">
        {/* Query editor */}
        <div className="border-b border-white/5 p-2">
          <textarea
            ref={textareaRef}
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onKeyDown={handleKeyDown}
            rows={4}
            className="w-full resize-none rounded border border-white/10 bg-[#12121a] px-3 py-2 font-mono text-xs text-white outline-none focus:border-blue-500/50"
            placeholder="Enter SQL query... (Ctrl+Enter to execute)"
          />
          <div className="mt-1 flex items-center justify-between">
            <span className="text-[10px] text-gray-600">Ctrl+Enter to execute</span>
            <button
              onClick={execute}
              disabled={running}
              className="flex items-center gap-1 rounded bg-green-600 px-3 py-1 text-xs text-white hover:bg-green-500 disabled:opacity-50 transition-colors"
            >
              {running ? <Loader2 size={12} className="animate-spin" /> : <Play size={12} />}
              Execute
            </button>
          </div>
        </div>

        {/* Results */}
        <div className="flex-1 overflow-hidden">
          <ResultsTable result={result} />
        </div>
      </div>
    </div>
  );
}

// IDENTITY_SEAL: PART-4 | role=DatabasePanelUI | inputs=connections,onExecuteQuery | outputs=JSX

"use client";

// ============================================================
// PART 1 ??Imports & Types
// ============================================================

import { useState, useCallback, useMemo } from "react";
import { Check, X, ChevronDown, ChevronUp, Columns, Rows, ArrowRight, ArrowLeft } from "lucide-react";

interface DiffHunk {
  id: number;
  startLine: number;
  endLine: number;
  addedLines: number;
  removedLines: number;
  status: "pending" | "accepted" | "rejected";
}

interface Props {
  original: string;
  modified: string;
  language?: string;
  fileName?: string;
  onAccept?: () => void;
  onReject?: () => void;
  onAcceptHunk?: (hunkId: number, content: string) => void;
  readOnly?: boolean;
}

// IDENTITY_SEAL: PART-1 | role=Types | inputs=none | outputs=DiffHunk,Props

// ============================================================
// PART 2 ??Hunk Parser
// ============================================================

function parseHunks(original: string, modified: string): DiffHunk[] {
  const origLines = original.split("\n");
  const modLines = modified.split("\n");
  const hunks: DiffHunk[] = [];
  let hunkId = 0;
  let i = 0, j = 0;
  let inHunk = false, hunkStart = 0, added = 0, removed = 0;
  const maxLen = Math.max(origLines.length, modLines.length);

  while (i < maxLen || j < maxLen) {
    const oLine = i < origLines.length ? origLines[i] : undefined;
    const mLine = j < modLines.length ? modLines[j] : undefined;
    if (oLine === mLine) {
      if (inHunk) {
        hunks.push({ id: hunkId++, startLine: hunkStart, endLine: Math.max(i, j), addedLines: added, removedLines: removed, status: "pending" });
        inHunk = false; added = 0; removed = 0;
      }
      i++; j++;
    } else {
      if (!inHunk) { inHunk = true; hunkStart = j + 1; }
      if (oLine !== undefined && mLine !== undefined) { added++; removed++; i++; j++; }
      else if (oLine === undefined) { added++; j++; }
      else { removed++; i++; }
    }
  }
  if (inHunk) hunks.push({ id: hunkId++, startLine: hunkStart, endLine: Math.max(i, j), addedLines: added, removedLines: removed, status: "pending" });
  return hunks;
}

// IDENTITY_SEAL: PART-2 | role=Parser | inputs=original,modified | outputs=DiffHunk[]

// ============================================================
// PART 3 ??Component
// ============================================================

export function DiffEditorPanel({ original, modified, language = "typescript", fileName, onAccept, onReject, onAcceptHunk, readOnly = false }: Props) {
  const [renderSideBySide, setRenderSideBySide] = useState(true);
  const [currentChangeIndex, setCurrentChangeIndex] = useState(0);
  const [hunks, setHunks] = useState<DiffHunk[]>(() => parseHunks(original, modified));

  const [prevInput, setPrevInput] = useState({ original, modified });
  if (prevInput.original !== original || prevInput.modified !== modified) {
    setPrevInput({ original, modified });
    setHunks(parseHunks(original, modified));
    setCurrentChangeIndex(0);
  }

  const stats = useMemo(() => ({
    added: hunks.reduce((s, h) => s + h.addedLines, 0),
    removed: hunks.reduce((s, h) => s + h.removedLines, 0),
    hunks: hunks.length,
  }), [hunks]);

  const navigateChange = useCallback((dir: "next" | "prev") => {
    if (hunks.length === 0) return;
    setCurrentChangeIndex((idx) => dir === "next" ? (idx + 1) % hunks.length : (idx - 1 + hunks.length) % hunks.length);
  }, [hunks]);

  const handleAcceptHunk = useCallback((hunkId: number) => {
    setHunks((prev) => prev.map((h) => h.id === hunkId ? { ...h, status: "accepted" as const } : h));
    onAcceptHunk?.(hunkId, modified);
  }, [modified, onAcceptHunk]);

  const handleRejectHunk = useCallback((hunkId: number) => {
    setHunks((prev) => prev.map((h) => h.id === hunkId ? { ...h, status: "rejected" as const } : h));
  }, []);

  const origLines = original.split("\n");
  const modLines = modified.split("\n");

  return (
    <div className="flex-1 flex flex-col overflow-hidden">
      <div className="flex items-center justify-between px-3 py-2 bg-[#0f1419] border-b border-white/8">
        <div className="flex items-center gap-3">
          {fileName && <span className="text-xs font-medium text-white">{fileName}</span>}
          <span className="text-[10px] text-white/50 flex items-center gap-2">
            <span className="text-green-400">+{stats.added}</span>
            <span className="text-red-400">-{stats.removed}</span>
            <span>{stats.hunks} changes</span>
          </span>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={() => setRenderSideBySide((p) => !p)}
            className="flex items-center gap-1 px-2 py-1 text-xs bg-white/5 text-white/50 hover:text-white rounded transition-colors">
            {renderSideBySide ? <Rows size={12} /> : <Columns size={12} />}
            {renderSideBySide ? "Inline" : "Side by Side"}
          </button>
          {hunks.length > 0 && (
            <div className="flex items-center gap-1">
              <button onClick={() => navigateChange("prev")} className="px-2 py-1 text-xs bg-white/5 text-white/50 hover:text-white rounded"><ChevronUp size={12} /></button>
              <span className="text-[10px] text-white/50 min-w-[3rem] text-center">{currentChangeIndex + 1}/{hunks.length}</span>
              <button onClick={() => navigateChange("next")} className="px-2 py-1 text-xs bg-white/5 text-white/50 hover:text-white rounded"><ChevronDown size={12} /></button>
            </div>
          )}
          {!readOnly && onAccept && (
            <button onClick={onAccept} className="flex items-center gap-1 px-3 py-1 text-xs bg-green-500/20 text-green-400 rounded hover:bg-green-500/30"><Check size={12} /> Accept All</button>
          )}
          {!readOnly && onReject && (
            <button onClick={onReject} className="flex items-center gap-1 px-3 py-1 text-xs bg-red-500/20 text-red-400 rounded hover:bg-red-500/30"><X size={12} /> Reject All</button>
          )}
        </div>
      </div>

      {!readOnly && hunks.length > 0 && (
        <div className="border-b border-white/8 bg-[#0a0e17] max-h-28 overflow-y-auto px-3 py-1">
          <div className="text-[10px] text-white/50 mb-1">Changes ({hunks.filter((h) => h.status === "pending").length} pending):</div>
          {hunks.map((hunk, idx) => (
            <div key={hunk.id} className={`flex items-center gap-2 text-[10px] px-1 py-0.5 rounded ${idx === currentChangeIndex ? "bg-white/5" : ""}`}>
              <span className="text-white/40 min-w-[4rem]">L{hunk.startLine}-{hunk.endLine}</span>
              <span className="text-green-400">+{hunk.addedLines}</span>
              <span className="text-red-400">-{hunk.removedLines}</span>
              {hunk.status === "pending" ? (
                <div className="flex items-center gap-1 ml-auto">
                  <button onClick={() => handleAcceptHunk(hunk.id)} className="flex items-center gap-0.5 px-1.5 py-0.5 text-green-400 hover:bg-green-500/20 rounded"><ArrowRight size={10} /> Accept</button>
                  <button onClick={() => handleRejectHunk(hunk.id)} className="flex items-center gap-0.5 px-1.5 py-0.5 text-red-400 hover:bg-red-500/20 rounded"><ArrowLeft size={10} /> Reject</button>
                </div>
              ) : (
                <span className={`ml-auto text-[10px] ${hunk.status === "accepted" ? "text-green-400" : "text-red-400"}`}>{hunk.status === "accepted" ? "Accepted" : "Rejected"}</span>
              )}
            </div>
          ))}
        </div>
      )}

      <div className="flex-1 overflow-auto bg-[#0a0e17] font-mono text-xs">
        {renderSideBySide ? (
          <div className="flex h-full">
            <div className="flex-1 overflow-auto border-r border-white/8 p-2">
              <div className="text-[10px] text-white/30 mb-1">Original</div>
              {origLines.map((line, i) => (
                <div key={i} className="flex"><span className="w-8 text-right pr-2 text-white/20 select-none">{i + 1}</span><span className="text-white/60">{line}</span></div>
              ))}
            </div>
            <div className="flex-1 overflow-auto p-2">
              <div className="text-[10px] text-white/30 mb-1">Modified</div>
              {modLines.map((line, i) => {
                const isChanged = i < origLines.length ? origLines[i] !== line : true;
                return (
                  <div key={i} className={`flex ${isChanged ? "bg-green-500/10" : ""}`}>
                    <span className="w-8 text-right pr-2 text-white/20 select-none">{i + 1}</span>
                    <span className={isChanged ? "text-green-400" : "text-white/60"}>{line}</span>
                  </div>
                );
              })}
            </div>
          </div>
        ) : (
          <div className="p-2">
            {modLines.map((line, i) => {
              const isChanged = i < origLines.length ? origLines[i] !== line : true;
              const wasRemoved = i < origLines.length && origLines[i] !== line;
              return (
                <div key={i}>
                  {wasRemoved && (
                    <div className="flex bg-red-500/10"><span className="w-8 text-right pr-2 text-white/20 select-none">-</span><span className="text-red-400 line-through">{origLines[i]}</span></div>
                  )}
                  <div className={`flex ${isChanged ? "bg-green-500/10" : ""}`}>
                    <span className="w-8 text-right pr-2 text-white/20 select-none">{isChanged ? "+" : " "}</span>
                    <span className={isChanged ? "text-green-400" : "text-white/60"}>{line}</span>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

// IDENTITY_SEAL: PART-3 | role=Component | inputs=Props | outputs=JSX

"use client";

// ============================================================
// PART 1 ??Imports & Types
// ============================================================

import { useState, useMemo } from "react";
import { GitCommit, GitBranch, GitMerge, ExternalLink } from "lucide-react";

export interface GitCommitNode {
  hash: string;
  shortHash: string;
  message: string;
  author: string;
  date: number;
  branch: string;
  parents: string[];
  isMerge: boolean;
}

export interface GitBranchInfo {
  name: string;
  color: string;
  headHash: string;
}

interface GitGraphProps {
  commits: GitCommitNode[];
  branches: GitBranchInfo[];
  currentBranch: string;
  onCheckout?: (hash: string) => void;
  onBranchClick?: (branch: string) => void;
}

// IDENTITY_SEAL: PART-1 | role=Types | inputs=none | outputs=GitCommitNode,GitBranchInfo

// ============================================================
// PART 2 ??Graph Layout
// ============================================================

const BRANCH_COLORS = ["#3b82f6", "#10b981", "#f59e0b", "#8b5cf6", "#ec4899", "#06b6d4", "#f97316"];
const LANE_WIDTH = 24;
const ROW_HEIGHT = 36;
const NODE_RADIUS = 5;

interface LayoutNode {
  commit: GitCommitNode;
  lane: number;
  color: string;
}

function computeLayout(commits: GitCommitNode[], branches: GitBranchInfo[]): LayoutNode[] {
  const branchColorMap = new Map<string, string>();
  branches.forEach((b, i) => branchColorMap.set(b.name, b.color || BRANCH_COLORS[i % BRANCH_COLORS.length]));

  const branchLaneMap = new Map<string, number>();
  let nextLane = 0;

  return commits.map((c) => {
    let lane = branchLaneMap.get(c.branch);
    if (lane == null) {
      lane = nextLane++;
      branchLaneMap.set(c.branch, lane);
    }
    return {
      commit: c,
      lane,
      color: branchColorMap.get(c.branch) ?? BRANCH_COLORS[lane % BRANCH_COLORS.length],
    };
  });
}

// IDENTITY_SEAL: PART-2 | role=GraphLayout | inputs=commits,branches | outputs=LayoutNode[]

// ============================================================
// PART 3 ??SVG Graph Renderer
// ============================================================

function GraphSVG({
  layoutNodes,
  selectedHash,
  onSelect,
}: {
  layoutNodes: LayoutNode[];
  selectedHash: string | null;
  onSelect: (hash: string) => void;
}) {
  const maxLane = Math.max(0, ...layoutNodes.map((n) => n.lane));
  const svgWidth = (maxLane + 1) * LANE_WIDTH + 20;
  const svgHeight = layoutNodes.length * ROW_HEIGHT + 20;

  const hashToIndex = new Map<string, number>();
  layoutNodes.forEach((n, i) => hashToIndex.set(n.commit.hash, i));

  return (
    <svg width={svgWidth} height={svgHeight} className="shrink-0">
      {/* Connection lines */}
      {layoutNodes.map((node, i) => {
        const x = node.lane * LANE_WIDTH + LANE_WIDTH / 2 + 10;
        const y = i * ROW_HEIGHT + ROW_HEIGHT / 2 + 10;
        return node.commit.parents.map((parentHash) => {
          const pi = hashToIndex.get(parentHash);
          if (pi == null) return null;
          const parent = layoutNodes[pi];
          const px = parent.lane * LANE_WIDTH + LANE_WIDTH / 2 + 10;
          const py = pi * ROW_HEIGHT + ROW_HEIGHT / 2 + 10;
          return (
            <path
              key={`${node.commit.hash}-${parentHash}`}
              d={node.lane === parent.lane
                ? `M${x},${y} L${px},${py}`
                : `M${x},${y} C${x},${(y + py) / 2} ${px},${(y + py) / 2} ${px},${py}`
              }
              fill="none"
              stroke={node.color}
              strokeWidth={1.5}
              opacity={0.5}
            />
          );
        });
      })}

      {/* Commit nodes */}
      {layoutNodes.map((node, i) => {
        const x = node.lane * LANE_WIDTH + LANE_WIDTH / 2 + 10;
        const y = i * ROW_HEIGHT + ROW_HEIGHT / 2 + 10;
        const isSelected = node.commit.hash === selectedHash;
        return (
          <g key={node.commit.hash} onClick={() => onSelect(node.commit.hash)} className="cursor-pointer">
            <circle
              cx={x}
              cy={y}
              r={node.commit.isMerge ? NODE_RADIUS + 2 : NODE_RADIUS}
              fill={isSelected ? "#fff" : node.color}
              stroke={isSelected ? node.color : "none"}
              strokeWidth={2}
            />
            {node.commit.isMerge && (
              <circle cx={x} cy={y} r={NODE_RADIUS - 1} fill="#1e1e2e" />
            )}
          </g>
        );
      })}
    </svg>
  );
}

