                  ))}
                </div>
              )}
              {currentQuestion.type === "multi-select" && currentQuestion.options && (
                <div className="grid grid-cols-2 gap-2">
                  {currentQuestion.options.map((opt) => {
                    const current = (getAnswer(currentQuestion.id) as string[]) ?? [];
                    const selected = Array.isArray(current) && current.includes(opt);
                    return (
                      <button key={opt} onClick={() => setAnswer(currentQuestion.id, selected ? current.filter((v) => v !== opt) : [...current, opt])}
                        className={`px-3 py-2 rounded-lg text-xs border text-left transition-colors ${selected ? "border-green-500 bg-green-500/10 text-green-400" : "border-white/10 hover:bg-white/5 text-white/50"}`}>{selected ? "??" : ""}{opt}</button>
                    );
                  })}
                </div>
              )}
              <div className="flex items-center justify-center gap-1 mt-6">
                {QUESTIONS.map((_, i) => (
                  <div key={i} className={`w-2 h-2 rounded-full transition-colors ${i === currentQ ? "bg-amber-500" : i < currentQ ? "bg-green-400" : "bg-white/10"}`} />
                ))}
              </div>
            </div>
          )}
          {step === "review" && (
            <div>
              <p className="text-sm font-medium text-white mb-3">紐낆꽭???뺤씤</p>
              <div className="space-y-2">
                {QUESTIONS.map((q) => {
                  const answer = getAnswer(q.id);
                  const text = Array.isArray(answer) ? answer.join(", ") : answer;
                  if (!text) return null;
                  return <div key={q.id} className="flex items-start gap-2 text-xs"><span className="text-white/40 min-w-[120px]">{q.question}</span><span className="text-white/70">{text}</span></div>;
                })}
              </div>
            </div>
          )}
        </div>
        <div className="flex items-center justify-between px-5 py-3 border-t border-white/8">
          <div>
            {step === "category" && title.trim() && (
              <button onClick={handleAutoFill} disabled={autoFilling}
                className="flex items-center gap-1 px-3 py-1.5 text-xs bg-amber-900/22 text-amber-400 rounded-lg hover:bg-amber-900/30 disabled:opacity-50">
                {autoFilling ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} />} AI ?먮룞 ?꾩꽦
              </button>
            )}
          </div>
          <div className="flex items-center gap-2">
            {step === "questions" && currentQ > 0 && (
              <button onClick={() => setCurrentQ((p) => p - 1)} className="flex items-center gap-1 px-3 py-1.5 text-xs text-white/40 hover:text-white"><ChevronLeft size={12} /> ?댁쟾</button>
            )}
            {step === "category" && <button onClick={() => { if (title.trim()) setStep("questions"); }} disabled={!title.trim()} className="flex items-center gap-1 px-4 py-1.5 text-xs bg-amber-800 text-stone-100 rounded-lg hover:bg-amber-700 disabled:opacity-30">?ㅼ쓬 <ChevronRight size={12} /></button>}
            {step === "questions" && currentQ < QUESTIONS.length - 1 && <button onClick={() => setCurrentQ((p) => p + 1)} className="flex items-center gap-1 px-4 py-1.5 text-xs bg-amber-800 text-stone-100 rounded-lg hover:bg-amber-700">?ㅼ쓬 <ChevronRight size={12} /></button>}
            {step === "questions" && currentQ === QUESTIONS.length - 1 && <button onClick={() => setStep("review")} className="flex items-center gap-1 px-4 py-1.5 text-xs bg-amber-800 text-stone-100 rounded-lg hover:bg-amber-700">?뺤씤 <Check size={12} /></button>}
            {step === "review" && <button onClick={handleComplete} className="flex items-center gap-1 px-4 py-1.5 text-xs bg-green-600 text-white rounded-lg hover:bg-green-700"><Sparkles size={12} /> ?꾨줈?앺듃 ?앹꽦</button>}
          </div>
        </div>
      </div>
    </div>
  );
}

