    const exists = relations.some(r =>
      (r.from === selFrom && r.to === selTo) || (r.from === selTo && r.to === selFrom)
    );
    if (exists) return;
    setConfig((prev: StoryConfig) => ({
      ...prev,
      charRelations: [...(prev.charRelations || []), { from: selFrom, to: selTo, type: selType, desc: relDesc }]
    }));
