    setState((prev) => {
      const scene = scenes[prev.sceneIndex];
      if (!scene) return prev;
      if (prev.beatIndex < scene.beats.length - 1) {
        return { ...prev, beatIndex: prev.beatIndex + 1 };
      }
      if (prev.sceneIndex < scenes.length - 1) {
        return { ...prev, sceneIndex: prev.sceneIndex + 1, beatIndex: 0 };
      }
      return { ...prev, isPlaying: false }; // ??r
    });
  }, [scenes]);

  useEffect(() => {
    if (!state.isPlaying || state.isPaused || !currentBeat) return;

    const duration = (currentBeat.text.length / 8) * 1000 / state.speed + 1500;
    autoPlayRef.current = setTimeout(() => goNext(), duration);
    return () => clearTimeout(autoPlayRef.current);
  }, [state.isPlaying, state.isPaused, state.sceneIndex, state.beatIndex, state.speed, currentBeat, goNext]);

  const goPrev = useCallback(() => {
    ttsRef.current?.stop();
    setState((prev) => {
      if (prev.beatIndex > 0) {
        return { ...prev, beatIndex: prev.beatIndex - 1 };
      }
      if (prev.sceneIndex > 0) {
        const prevScene = scenes[prev.sceneIndex - 1];
        return { ...prev, sceneIndex: prev.sceneIndex - 1, beatIndex: prevScene.beats.length - 1 };
      }
      return prev;
    });
  }, [scenes]);

  const togglePlay = useCallback(() => {
    setState((prev) => {
      if (prev.isPaused) return { ...prev, isPaused: false };
      if (prev.isPlaying) return { ...prev, isPaused: true };
      return { ...prev, isPlaying: true, isPaused: false };
    });
  }, []);

  const toggleFullscreen = useCallback(() => {
    if (!containerRef.current) return;
    if (document.fullscreenElement) document.exitFullscreen();
    else containerRef.current.requestFullscreen();
    setState((p) => ({ ...p, fullscreen: !p.fullscreen }));
  }, []);

  const canPrev = state.sceneIndex > 0 || state.beatIndex > 0;
  const particles = currentScene?.mood
    ? (currentScene.mood === "rainy" ? "rain" : currentScene.mood === "snowy" ? "snow" : "none") as ParticleType
    : "none";

  // ?ㅻ낫??r
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.key === "ArrowRight" || e.key === " ") { e.preventDefault(); goNext(); }
      if (e.key === "ArrowLeft") { e.preventDefault(); goPrev(); }
      if (e.key === "Escape" && onClose) onClose();
      if (e.key === "p") togglePlay();
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [goNext, goPrev, onClose, togglePlay]);

  if (!currentScene || !currentBeat) {
    return (
      <div className="flex items-center justify-center h-full bg-bg-primary text-text-secondary">
        {scenes.length === 0 ? "?뚯떛???λ㈃???놁뒿?덈떎." : "?ъ깮 ?꾨즺"}
      </div>
    );
  }

  const bgUrl = backgroundUrls?.get(currentScene.id);
  const bgGradient = getMoodGradient(currentScene.mood, currentScene.timeOfDay);

  return (
    <div ref={containerRef} className="relative w-full h-full overflow-hidden select-none" style={{ background: bgGradient }}>
      {/* ?? ?쇰뵒??紐⑤뱶: ?대몺 + 理쒖냼 鍮꾩＜???? */}
      {isRadio && (
        <>
          <div className="absolute inset-0 bg-black" />
          {/* 以묒븰 ?뚮룞 ?댄럺??*/}
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
            <div className={`rounded-full border border-accent-purple/20 ${state.isPlaying && !state.isPaused ? 'animate-ping' : ''}`} style={{ width: 120, height: 120 }} />
            <div className="absolute rounded-full border border-accent-purple/10" style={{ width: 200, height: 200 }} />
            <Headphones className="absolute h-8 w-8 text-accent-purple/40" />
          </div>
          {/* ?쇰뵒??紐⑤뱶?먯꽌??鍮꾪듃 ?띿뒪???섏씠?쒖씤 */}
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none px-16">
            <p className={`text-center leading-loose transition-opacity duration-1000 max-w-xl ${
              currentBeat.type === 'dialogue' ? 'text-lg text-text-primary font-medium' :
              currentBeat.type === 'thought' ? 'text-base text-accent-purple/80 italic' :
              currentBeat.type === 'description' ? 'text-sm text-text-tertiary' :
              'text-base text-text-secondary'
            }`} style={{ opacity: 0.8 }}>
              {currentBeat.speaker && currentBeat.type === 'dialogue' && (
                <span className="block text-xs text-accent-green/60 font-mono mb-2">{currentBeat.speaker}</span>
              )}
              {currentBeat.text}
            </p>
          </div>
        </>
      )}

      {/* ?? 鍮꾩＜???몃꺼 紐⑤뱶: ? 鍮꾩＜???? */}
      {!isRadio && (
        <>
          {/* 諛곌꼍 ?대?吏 */}
          {bgUrl && (
            <div
              className="absolute inset-0 bg-cover bg-center transition-opacity duration-1000"
              style={{ backgroundImage: `url(${bgUrl})`, filter: getMoodFilter(currentScene.mood), opacity: 0.6 }}
            />
          )}

          {/* ?뚰떚??*/}
          <ParticleLayer type={particles} />
        </>
      )}

      {/* 鍮꾨꽕??(?묒そ 紐⑤뱶) */}
      <div className="absolute inset-0 pointer-events-none" style={{ background: isRadio ? "radial-gradient(ellipse at center, transparent 30%, rgba(0,0,0,0.8) 100%)" : "radial-gradient(ellipse at center, transparent 50%, rgba(0,0,0,0.4) 100%)" }} />

      {/* ?λ㈃ ??댄? (?꾪솚 ?? */}
      <div className="absolute top-6 left-6 right-6 flex items-center justify-between z-10">
        <div className="flex items-center gap-3">
          <span className={`text-[10px] font-mono bg-bg-primary/40 backdrop-blur-sm rounded px-2 py-0.5 ${isRadio ? 'text-accent-purple' : 'text-text-tertiary'}`}>
            {isRadio ? '?렒' : '?렗'} {currentScene.title} {currentScene.timeOfDay ? `쨌 ${currentScene.timeOfDay}` : ""}
          </span>
          <span className="text-[9px] text-text-tertiary">
            {currentGlobalBeat}/{totalBeats}
          </span>
        </div>

        {/* 而⑦듃濡?*/}
        <div className="flex items-center gap-1">
          <button onClick={() => setState((p) => ({ ...p, voiceEnabled: !p.voiceEnabled }))} className="p-1.5 rounded-lg hover:bg-white/10 transition-colors" aria-label="?뚯꽦 ?좉?">
            {state.voiceEnabled ? <Volume2 className="h-3.5 w-3.5 text-text-secondary" /> : <VolumeX className="h-3.5 w-3.5 text-text-tertiary" />}
          </button>
          <button onClick={() => setState((p) => ({ ...p, showOverlay: !p.showOverlay }))} className="p-1.5 rounded-lg hover:bg-white/10 transition-colors" aria-label="硫뷀듃由??좉?">
            <BarChart3 className="h-3.5 w-3.5 text-text-secondary" />
          </button>
          <select
            value={state.speed}
            onChange={(e) => setState((p) => ({ ...p, speed: Number(e.target.value) }))}
            className="bg-transparent text-[10px] text-text-tertiary border-none outline-none cursor-pointer"
          >
            <option value={0.5}>0.5x</option>
            <option value={0.75}>0.75x</option>
            <option value={1}>1x</option>
            <option value={1.5}>1.5x</option>
            <option value={2}>2x</option>
          </select>
          <button onClick={toggleFullscreen} className="p-1.5 rounded-lg hover:bg-white/10 transition-colors" aria-label="?꾩껜?붾㈃">
            {state.fullscreen ? <Minimize2 className="h-3.5 w-3.5 text-text-secondary" /> : <Maximize2 className="h-3.5 w-3.5 text-text-secondary" />}
          </button>
          {onClose && (
            <button onClick={onClose} className="p-1.5 rounded-lg hover:bg-white/10 transition-colors" aria-label="?リ린">
              <X className="h-3.5 w-3.5 text-text-secondary" />
            </button>
          )}
        </div>
      </div>

      {/* ?ъ깮 而⑦듃濡?(?섎떒 以묒븰) */}
      <div className="absolute bottom-28 left-1/2 -translate-x-1/2 flex items-center gap-2 z-10">
        <button onClick={goPrev} disabled={!canPrev} className="p-2 rounded-full bg-bg-primary/30 backdrop-blur-sm hover:bg-white/10 disabled:opacity-20 transition-colors" aria-label="?댁쟾 鍮꾪듃">
          <SkipBack className="h-4 w-4 text-text-secondary" />
        </button>
        <button onClick={togglePlay} className="p-3 rounded-full bg-accent-purple/30 backdrop-blur-sm hover:bg-accent-purple/50 transition-colors" aria-label={state.isPlaying && !state.isPaused ? "?쇱떆?뺤?" : "?ъ깮"}>
          {state.isPlaying && !state.isPaused ? <Pause className="h-5 w-5 text-accent-purple" /> : <Play className="h-5 w-5 text-accent-purple" />}
        </button>
        <button onClick={goNext} className="p-2 rounded-full bg-bg-primary/30 backdrop-blur-sm hover:bg-white/10 transition-colors" aria-label="?ㅼ쓬 鍮꾪듃">
          <SkipForward className="h-4 w-4 text-text-secondary" />
        </button>
      </div>

      {/* 罹먮┃???쒖떆 (鍮꾩＜??紐⑤뱶留? */}
      {!isRadio && currentBeat.speaker && (
        <>
          {/* 罹먮┃???대?吏 (?덉쑝硫? */}
          {characterImages?.get(currentBeat.speaker)?.get(getDominantEmotion(currentBeat.emotion)) ? (
            <div className="absolute bottom-32 left-8 transition-all duration-500">
              <img
                src={characterImages?.get(currentBeat.speaker)?.get(getDominantEmotion(currentBeat.emotion)) ?? ''}
                alt={currentBeat.speaker}
                className="h-64 object-contain drop-shadow-2xl"
              />
              <div className="text-center mt-1 bg-bg-secondary/80 backdrop-blur-sm rounded-lg px-3 py-1 border border-border/30">
                <span className="text-xs font-mono text-accent-purple">{currentBeat.speaker}</span>
              </div>
            </div>
          ) : (
            <CharacterDisplay name={currentBeat.speaker} emotion={currentBeat.emotion} side="left" />
          )}
        </>
      )}

      {/* ??ъ갹 (鍮꾩＜??紐⑤뱶), ?쇰뵒?ㅻ뒗 以묒븰 ?띿뒪?몃줈 ?泥?*/}
      {!isRadio && <DialogueBox
        beat={currentBeat}
        speed={state.speed}
        onNext={goNext}
        onPrev={goPrev}
        canPrev={canPrev}
        showMetrics={state.showOverlay}
        tension={currentScene.tension}
      />}

      {/* ?쇰뵒??紐⑤뱶 ?섎떒: 媛꾨떒???ㅼ쓬 踰꾪듉 */}
      {isRadio && (
        <div className="absolute bottom-12 left-0 right-0 flex justify-center gap-4">
          <button onClick={goPrev} disabled={!canPrev} className="p-2 rounded-full bg-white/5 hover:bg-white/10 disabled:opacity-20 transition-colors" aria-label="?댁쟾">
            <ChevronLeft className="h-5 w-5 text-text-secondary" />
          </button>
          <button onClick={goNext} className="px-6 py-2 bg-accent-purple/15 hover:bg-accent-purple/25 text-accent-purple rounded-full text-sm font-mono transition-colors">
            ?ㅼ쓬
          </button>
        </div>
      )}

      {/* 吏꾪뻾瑜?諛?*/}
      <div className="absolute bottom-0 left-0 right-0 h-1 bg-bg-primary/30">
        <div
          className="h-full bg-accent-purple/60 transition-all duration-300"
          style={{ width: `${(currentGlobalBeat / totalBeats) * 100}%` }}
        />
      </div>
    </div>
  );
}

// IDENTITY_SEAL: PART-7 | role=main-player | inputs=ScenePlayerProps | outputs=visual-novel-UI

usedDeprecatedRules.source:
"use client";

// ============================================================
// SceneTimeline ???몄쭛 紐⑤뱶 (??꾨씪???먮뵒??
// ============================================================
// ?뚯떛???λ㈃/鍮꾪듃瑜???꾨씪?몄쑝濡??쒓컖??
// ?쒕옒洹??쒖꽌 蹂寃? ??젣, 蹂묓빀, 臾몄젣 ?ㅽ뙚 ?쒖떆.
// ?몄쭛 ???먭퀬 ??룞湲고솕.

import { useState, useCallback, useEffect, useMemo, useRef } from "react";
import {
  Play, GripVertical, Trash2, Merge, Split, AlertTriangle,
  Eye, RotateCcw, Save, Wand2, ChevronDown, ChevronRight,
} from "lucide-react";
import type { ParsedScene, SceneBeat, BeatType } from "@/engine/scene-parser";
import type { AppLanguage } from "@/lib/studio-types";

// ============================================================
// PART 1 ??Types
// ============================================================

interface SceneTimelineProps {
  scenes: ParsedScene[];
  language: AppLanguage;
  onScenesChange: (scenes: ParsedScene[]) => void;
  onPlayFrom?: (sceneIndex: number, beatIndex: number) => void;
  onExportText?: (text: string) => void;
  warnings?: string[];
}

interface DragState {
  sceneIndex: number;
  beatIndex: number;
}

// IDENTITY_SEAL: PART-1 | role=types | inputs=none | outputs=SceneTimelineProps

// ============================================================
// PART 2 ??鍮꾪듃 ????쒓컖??r
// ============================================================

const BEAT_COLORS: Record<BeatType, string> = {
  dialogue: "bg-accent-green/30 border-accent-green/50",
  narration: "bg-accent-blue/20 border-accent-blue/40",
  action: "bg-accent-amber/25 border-accent-amber/45",
  thought: "bg-accent-purple/25 border-accent-purple/45",
  description: "bg-bg-tertiary/60 border-border/40",
};

const BEAT_LABELS: Record<BeatType, string> = {
  dialogue: "???

?쒖닠",
  action: "?됰룞",
  thought: "?대㈃",
  description: "臾섏궗",
};

const BEAT_ICONS: Record<BeatType, string> = {
  dialogue: "?뮠",
  narration: "?뱷",
  action: "??

?뮡",
  description: "?똾",
};

// IDENTITY_SEAL: PART-2 | role=beat-visuals | inputs=BeatType | outputs=colors,labels,icons

// ============================================================
// PART 3 ??臾몄젣 媛먯?
// ============================================================

interface TimelineWarning {
  sceneIndex: number;
  beatIndex?: number;
  message: string;
  severity: "critical" | "warning" | "info";
}

function detectTimelineWarnings(scenes: ParsedScene[]): TimelineWarning[] {
  const warnings: TimelineWarning[] = [];

  for (let si = 0; si < scenes.length; si++) {
    const scene = scenes[si];
    const beats = scene.beats;

    // ????놁씠 ?쒖닠 8鍮꾪듃 ?댁긽
    const dialogueCount = beats.filter((b) => b.type === "dialogue").length;
    if (beats.length > 8 && dialogueCount === 0) {
      warnings.push({ sceneIndex: si, message: `????놁씠 ?쒖닠留?${beats.length}鍮꾪듃`, severity: "warning" });
    }

    // 媛숈? ???5?곗냽
    let streak = 1;
    for (let bi = 1; bi < beats.length; bi++) {
      if (beats[bi].type === beats[bi - 1].type) {
        streak++;
        if (streak >= 5) {
          warnings.push({ sceneIndex: si, beatIndex: bi, message: `${BEAT_LABELS[beats[bi].type]} ${streak}?곗냽 ???⑥“濡쒖?`, severity: "warning" });
          break;
        }
      } else { streak = 1; }
    }

    // ?먯뀡 湲됰씫 (?댁쟾 ?λ㈃ ?鍮?-30 ?댁긽)
    if (si > 0) {
      const prevTension = scenes[si - 1].tension;
      const drop = prevTension - scene.tension;
      if (drop >= 30) {
        warnings.push({ sceneIndex: si, message: `?먯뀡 湲됰씫 ${prevTension}??{scene.tension} (-${drop})`, severity: "critical" });
      }
    }

    // ?붿옄 誘명솗?????r
    const noSpeaker = beats.filter((b) => b.type === "dialogue" && !b.speaker).length;
    if (noSpeaker > 0) {
      warnings.push({ sceneIndex: si, message: `?붿옄 誘명솗?????${noSpeaker}嫄?, severity: "info" });
    }
  }

  return warnings;
}

// IDENTITY_SEAL: PART-3 | role=warning-detection | inputs=ParsedScene[] | outputs=TimelineWarning[]

// ============================================================
// PART 4 ??鍮꾪듃 釉붾줉 而댄룷?뚰듃
// ============================================================

function BeatBlock({
  beat,
  sceneIndex,
  beatIndex,
  isSelected,
  warning,
  onSelect,
  onDelete,
  onDragStart,
  onDragOver,
  onDrop,
}: {
  beat: SceneBeat;
  sceneIndex: number;
  beatIndex: number;
  isSelected: boolean;
  warning?: TimelineWarning;
  onSelect: () => void;
  onDelete: () => void;
  onDragStart: () => void;
  onDragOver: (e: React.DragEvent) => void;
  onDrop: () => void;
}) {
  return (
    <div
      draggable
      onDragStart={onDragStart}
      onDragOver={(e) => { e.preventDefault(); onDragOver(e); }}
      onDrop={onDrop}
      onClick={onSelect}
      className={`group relative flex items-start gap-2 px-2 py-1.5 rounded-lg border cursor-pointer transition-all
        ${BEAT_COLORS[beat.type]}
        ${isSelected ? "ring-1 ring-accent-purple" : ""}
        ${warning ? "ring-1 ring-accent-amber/50" : ""}
        hover:brightness-110`}
    >
      {/* ?쒕옒洹??몃뱾 */}
      <div className="opacity-0 group-hover:opacity-50 cursor-grab active:cursor-grabbing pt-0.5">
        <GripVertical className="h-3 w-3 text-text-tertiary" />
      </div>

      {/* ?꾩씠肄?+ ?댁슜 */}
      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-1.5 mb-0.5">
          <span className="text-[10px]">{BEAT_ICONS[beat.type]}</span>
          {beat.speaker && (
            <span className="text-[9px] font-mono text-accent-green truncate">{beat.speaker}</span>
          )}
          <span className="text-[8px] text-text-tertiary">{BEAT_LABELS[beat.type]}</span>
        </div>
        <div className="text-[11px] text-text-primary leading-tight truncate">{beat.text}</div>
      </div>

      {/* 寃쎄퀬 ?꾩씠肄?*/}
      {warning && (
        <div className="absolute -top-1 -right-1">
          <AlertTriangle className="h-3 w-3 text-accent-amber" />
        </div>
      )}

      {/* ??젣 (?몃쾭) */}
      <button
        onClick={(e) => { e.stopPropagation(); onDelete(); }}
        className="opacity-0 group-hover:opacity-100 p-0.5 rounded hover:bg-accent-red/20 transition-opacity"
        aria-label="??젣"
      >
        <Trash2 className="h-3 w-3 text-accent-red" />
      </button>
    </div>
  );
}

// IDENTITY_SEAL: PART-4 | role=beat-block | inputs=SceneBeat,callbacks | outputs=draggable-beat-UI

// ============================================================
// PART 5 ???λ㈃ ?덉씤 而댄룷?뚰듃
// ============================================================

function SceneLane({
  scene,
  sceneIndex,
  collapsed,
  onToggle,
  selectedBeat,
  sceneWarnings,
  onSelectBeat,
  onDeleteBeat,
  onPlayFrom,
  onDragStart,
  onDragOver,
  onDrop,
}: {
  scene: ParsedScene;
  sceneIndex: number;
  collapsed: boolean;
  onToggle: () => void;
  selectedBeat: { sceneIndex: number; beatIndex: number } | null;
  sceneWarnings: TimelineWarning[];
  onSelectBeat: (si: number, bi: number) => void;
  onDeleteBeat: (si: number, bi: number) => void;
  onPlayFrom?: (si: number, bi: number) => void;
  onDragStart: (si: number, bi: number) => void;
  onDragOver: (si: number, bi: number, e: React.DragEvent) => void;
  onDrop: (si: number, bi: number) => void;
}) {
  const dialogueCount = scene.beats.filter((b) => b.type === "dialogue").length;
  const beatCount = scene.beats.length;
  const hasWarnings = sceneWarnings.length > 0;

  return (
    <div className={`border rounded-xl ${hasWarnings ? "border-accent-amber/30" : "border-border/20"} bg-bg-secondary/30`}>
      {/* ?λ㈃ ?ㅻ뜑 */}
      <div className="flex items-center gap-2 px-3 py-2 cursor-pointer hover:bg-white/[0.02] transition-colors" onClick={onToggle}>
        {collapsed ? <ChevronRight className="h-3.5 w-3.5 text-text-tertiary" /> : <ChevronDown className="h-3.5 w-3.5 text-text-tertiary" />}

        <span className="text-xs font-mono text-text-primary font-medium">{scene.title}</span>

        {scene.timeOfDay && <span className="text-[9px] text-text-tertiary">{scene.timeOfDay}</span>}

        {/* ?먯뀡 諛?*/}
        <div className="flex-1 flex items-center gap-1.5 mx-2">
          <div className="h-1.5 flex-1 bg-bg-tertiary/50 rounded-full overflow-hidden">
            <div
              className={`h-full rounded-full transition-all ${scene.tension > 70 ? "bg-accent-red" : scene.tension > 40 ? "bg-accent-amber" : "bg-accent-green"}`}
              style={{ width: `${scene.tension}%` }}
            />
          </div>
          <span className="text-[9px] text-text-tertiary w-5 text-right">{scene.tension}</span>
        </div>

        {/* ?듦퀎 */}
        <span className="text-[9px] text-text-tertiary">{beatCount}鍮꾪듃 쨌 ?뮠{dialogueCount}</span>

        {hasWarnings && <AlertTriangle className="h-3 w-3 text-accent-amber" />}

        {onPlayFrom && (
          <button onClick={(e) => { e.stopPropagation(); onPlayFrom(sceneIndex, 0); }} className="p-1 rounded hover:bg-accent-purple/20 transition-colors" aria-label="???λ㈃遺???ъ깮">
            <Play className="h-3 w-3 text-accent-purple" />
          </button>
        )}
      </div>

      {/* 鍮꾪듃 紐⑸줉 */}
      {!collapsed && (
        <div className="px-2 pb-2 space-y-1">
          {scene.beats.map((beat, bi) => {
            const beatWarning = sceneWarnings.find((w) => w.beatIndex === bi);
            return (
              <BeatBlock
                key={beat.id}
                beat={beat}
                sceneIndex={sceneIndex}
                beatIndex={bi}
                isSelected={selectedBeat?.sceneIndex === sceneIndex && selectedBeat?.beatIndex === bi}
                warning={beatWarning}
                onSelect={() => onSelectBeat(sceneIndex, bi)}
                onDelete={() => onDeleteBeat(sceneIndex, bi)}
                onDragStart={() => onDragStart(sceneIndex, bi)}
                onDragOver={(e) => onDragOver(sceneIndex, bi, e)}
                onDrop={() => onDrop(sceneIndex, bi)}
              />
            );
          })}
          {/* ?λ㈃ ?덈꺼 寃쎄퀬 */}
          {sceneWarnings.filter((w) => w.beatIndex === undefined).map((w, i) => (
