          </h3>
          <span className="text-[9px] text-text-tertiary">{scenes.length}?λ㈃ 쨌 {totalBeats}鍮꾪듃</span>
        </div>

        <div className="flex items-center gap-1.5">
          <button onClick={undo} disabled={undoStack.length === 0} className="p-1.5 rounded-lg hover:bg-white/5 disabled:opacity-20 transition-colors text-text-secondary" aria-label="?섎룎由ш린">
            <RotateCcw className="h-3.5 w-3.5" />
          </button>
          <button onClick={handleExport} className="p-1.5 rounded-lg hover:bg-white/5 transition-colors text-text-secondary" aria-label="?먭퀬 ?대낫?닿린">
            <Save className="h-3.5 w-3.5" />
          </button>
        </div>
      </div>

      {/* 鍮꾩쑉 諛?*/}
      <div className="flex h-2 mx-3 mt-2 rounded-full overflow-hidden bg-bg-tertiary/30">
        {(["dialogue", "narration", "action", "thought", "description"] as BeatType[]).map((type) => (
          <div
            key={type}
            className={BEAT_COLORS[type].split(" ")[0]}
            style={{ width: `${(typeDistribution[type] / Math.max(1, totalBeats)) * 100}%` }}
            title={`${BEAT_LABELS[type]}: ${typeDistribution[type]}媛?(${Math.round((typeDistribution[type] / Math.max(1, totalBeats)) * 100)}%)`}
          />
        ))}
      </div>
      <div className="flex items-center gap-3 px-3 py-1">
        {(["dialogue", "narration", "action", "thought", "description"] as BeatType[]).map((type) => (
          <span key={type} className="flex items-center gap-1 text-[8px] text-text-tertiary">
            <span>{BEAT_ICONS[type]}</span>
            {BEAT_LABELS[type]} {typeDistribution[type]}
          </span>
        ))}
      </div>

      {/* 寃쎄퀬 諛곕꼫 */}
      {timelineWarnings.filter((w) => w.severity === "critical").length > 0 && (
        <div className="mx-3 mt-1 px-3 py-1.5 bg-accent-red/10 border border-accent-red/20 rounded-lg flex items-center gap-2 text-[10px] text-accent-red">
          <AlertTriangle className="h-3.5 w-3.5 flex-shrink-0" />
          {isKO ? "?먯뀡 湲됰씫 媛먯? ???낆옄 ?댄깉 ?꾪뿕 援ш컙???덉뒿?덈떎" : "Tension drop detected ??risk of reader dropout"}
        </div>
      )}

      {/* ?λ㈃ 紐⑸줉 */}
      <div className="flex-1 overflow-y-auto px-3 py-2 space-y-2">
        {scenes.map((scene, si) => (
          <SceneLane
            key={scene.id}
            scene={scene}
            sceneIndex={si}
            collapsed={collapsedScenes.has(si)}
            onToggle={() => setCollapsedScenes((prev) => {
              const next = new Set(prev);
