            onDeleteBeat={deleteBeat}
            onPlayFrom={onPlayFrom}
            onDragStart={(si2, bi) => setDragSource({ sceneIndex: si2, beatIndex: bi })}
            onDragOver={(si2, bi, e) => e.preventDefault()}
            onDrop={(si2, bi) => handleDrop(si2, bi)}
          />
        ))}
      </div>
    </div>
  );
}

