  listUserProjects,
  supabaseAnonKey,
  supabaseUrl,
} from '@/lib/supabase';
import { useAppDialog } from '@/hooks/useAppDialog';
import { AppDialog } from '@/components/ui/AppDialog';
import {
  PROJECT_LIBRARY_KEY,
  MAX_LOCAL_PROJECTS,
  REFERENCE_TEXT_LIMIT,
  STORY_BIBLE_LIMIT,
  PROVIDERS,
  WORKSPACE_TAB_STORAGE_KEY,
  type WorkspaceTab,
  type TranslatorBackgroundMode,
