function makeCharacter(name: string, overrides?: Partial<Character>): Character {
  return {
    id: `char-${name}`,
    name,
    role: '二쇱씤怨?,
    traits: '',
    appearance: '',
    dna: 0,
    ...overrides,
  };
}

function makeManuscript(
  episode: number,
  content: string,
  title?: string,
): EpisodeManuscript {
