import { useState, useEffect, useRef } from 'react';
import type { AdvancedWritingSettings } from '@/components/studio/AdvancedWritingPanel';

type WritingMode = 'ai' | 'edit' | 'canvas' | 'refine' | 'advanced';

const DEFAULT_ADVANCED: AdvancedWritingSettings = {
  sceneGoals: [],
  constraints: { pov: '3rd-limited', dialogueRatio: 40, tempo: 'stable', sentenceLen: 'normal', emotionExposure: 'normal' },
  references: { prevEpisodes: 3, characterCards: true, worldSetting: true, styleProfile: false, sceneSheet: false, platformPreset: false },
  locks: { speechStyle: false, worldRules: false, charRelations: false, bannedWords: false },
  outputMode: 'draft', includes: '', excludes: '',
};

/**
 * Manages writing mode state (ai/edit/canvas/refine/advanced) with per-session editDraft persistence.
 * @param currentSessionId - Active session for draft isolation
 * @param hydrated - Whether localStorage has been loaded (prevents SSR flash)
 */
export function useStudioWritingMode(currentSessionId: string | null, hydrated: boolean) {
  const [writingMode, setWritingMode] = useState<WritingMode>('ai');
  const [editDraft, setEditDraft] = useState('');
  const editDraftRef = useRef<HTMLTextAreaElement>(null);
  const [advancedSettings, setAdvancedSettings] = useState<AdvancedWritingSettings>(DEFAULT_ADVANCED);
  const [canvasContent, setCanvasContent] = useState('');
  const [canvasPass, setCanvasPass] = useState(() => {
    if (typeof window !== 'undefined') {
      const saved = sessionStorage.getItem('noa_canvasPass');
      return saved ? parseInt(saved, 10) : 0;
    }
    return 0;
  });
  const [promptDirective, setPromptDirective] = useState('');

  // canvasPass persist
  useEffect(() => {
    if (canvasPass > 0) sessionStorage.setItem('noa_canvasPass', String(canvasPass));
    else sessionStorage.removeItem('noa_canvasPass');
  }, [canvasPass]);

  // editDraft ?몄뀡蹂??꾩떆 ???蹂듭썝
  // hydration ??localStorage?먯꽌 蹂듭썝 ???섎룄??setState
  useEffect(() => {
    if (!hydrated || !currentSessionId) return;
    const saved = localStorage.getItem(`noa_editdraft_${currentSessionId}`);
    if (saved !== null) {
      // eslint-disable-next-line react-hooks/purity
      setEditDraft(saved);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentSessionId, hydrated]);

  useEffect(() => {
    if (!currentSessionId || !hydrated) return;
    const key = `noa_editdraft_${currentSessionId}`;
    if (editDraft) {
      localStorage.setItem(key, editDraft);
    } else {
      const timer = setTimeout(() => {
        if (!editDraft) localStorage.removeItem(key);
      }, 2000);
      return () => clearTimeout(timer);
    }
  }, [editDraft, currentSessionId, hydrated]);

  return {
    writingMode, setWritingMode,
    editDraft, setEditDraft,
    editDraftRef,
    advancedSettings, setAdvancedSettings,
    canvasContent, setCanvasContent,
    canvasPass, setCanvasPass,
    promptDirective, setPromptDirective,
  };
}

"use client";

import { createContext, useContext, useState, useEffect, useCallback, useRef, ReactNode } from 'react';
import type { User, Auth } from 'firebase/auth';
import { app, lazyFirebaseAuth } from './firebase';
import { logger } from '@/lib/logger';

interface AuthContextType {
  user: User | null;
  /** Firebase UID ??EH Translator쨌?ㅽ듃?뚰겕 API ?깆뿉 ?ъ슜 */
  userId: string | null;
  loading: boolean;
  signInWithGoogle: () => Promise<void>;
  signOut: () => Promise<void>;
  isConfigured: boolean;
  error: string | null;
  accessToken: string | null;
  refreshAccessToken: () => Promise<string | null>;
  /** Firebase ID ?좏겙 (Bearer API ???ㅽ듃?뚰겕 ?먯씠?꾪듃 ?? */
  getIdToken: () => Promise<string | null>;
}

// #22: Default values throw to surface missing AuthProvider early
const AuthContext = createContext<AuthContextType>({
  user: null,
  userId: null,
  loading: false,
  signInWithGoogle: async () => { throw new Error('AuthProvider not mounted'); },
  signOut: async () => { throw new Error('AuthProvider not mounted'); },
  isConfigured: false,
  error: null,
  accessToken: null,
  refreshAccessToken: async () => { throw new Error('AuthProvider not mounted'); },
  getIdToken: async () => { throw new Error('AuthProvider not mounted'); },
});

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [accessToken, setAccessToken] = useState<string | null>(null);
  const isConfigured = app !== null;

  // Mutex for token refresh ??prevents concurrent refresh popups
  const refreshPromiseRef = useRef<Promise<string | null> | null>(null);

  useEffect(() => {
    let unsubscribe: (() => void) | undefined;
    lazyFirebaseAuth().then((resolvedAuth) => {
      if (!resolvedAuth) {
        setLoading(false);
        return;
      }
      import('firebase/auth').then(({ onAuthStateChanged, getRedirectResult }) => {
        getRedirectResult(resolvedAuth).catch(() => {});
        unsubscribe = onAuthStateChanged(resolvedAuth, (u) => {
          setUser(u);
          setLoading(false);
          if (!u) setAccessToken(null);
        });
      });
    });
    return () => { if (unsubscribe) unsubscribe(); };
  }, []);

  const signInWithGoogle = async () => {
    const resolvedAuth = await lazyFirebaseAuth();
    if (!resolvedAuth) {
      logger.error('Auth', 'Firebase auth is null ??not initialized');
      setError('Firebase媛 珥덇린?붾릺吏 ?딆븯?듬땲?? ?섍꼍蹂?섎? ?뺤씤?댁＜?몄슂.');
      return;
    }
    logger.info('Auth', 'signInWithGoogle called');
    setError(null);
    try {
      const { signInWithPopup, signInWithRedirect, GoogleAuthProvider } = await import('firebase/auth');
      const provider = new GoogleAuthProvider();
      provider.setCustomParameters({ 
        prompt: 'select_account consent',
        access_type: 'offline' 
      });
      provider.addScope('https://www.googleapis.com/auth/drive.file');
      const isMobile = /iPhone|iPad|Android/i.test(navigator.userAgent);
      if (isMobile) {
        await signInWithRedirect(resolvedAuth, provider);
        return; 
      }
      const result = await signInWithPopup(resolvedAuth, provider);
      const credential = GoogleAuthProvider.credentialFromResult(result);
      setAccessToken(credential?.accessToken ?? null);
    } catch (err: unknown) {
      const code = (err as { code?: string })?.code ?? '';
      const msg = (err as { message?: string })?.message ?? '';
      if (code === 'auth/popup-closed-by-user' || code === 'auth/cancelled-popup-request') return;
      setError(`濡쒓렇???ㅽ뙣: ${code || msg}`);
      logger.error('Auth', 'signInWithGoogle error:', code, msg);
    }
  };

  const refreshAccessToken = useCallback(async (): Promise<string | null> => {
    const resolvedAuth = await lazyFirebaseAuth();
    if (!resolvedAuth) return null;

    // Mutex: if a refresh is already in progress, await the same promise
    if (refreshPromiseRef.current) {
      return refreshPromiseRef.current;
    }

    const doRefresh = async (): Promise<string | null> => {
      try {
        const { GoogleAuthProvider, reauthenticateWithPopup, signInWithPopup } = await import('firebase/auth');
        
        const provider = new GoogleAuthProvider();
        provider.addScope('https://www.googleapis.com/auth/drive.file');

        let credential: import('firebase/auth').OAuthCredential | null = null;
        const currentUser = resolvedAuth.currentUser;

        if (currentUser) {
          try {
            const result = await reauthenticateWithPopup(currentUser, provider);
            credential = GoogleAuthProvider.credentialFromResult(result);
          } catch {
            const result = await signInWithPopup(resolvedAuth, provider);
            credential = GoogleAuthProvider.credentialFromResult(result);
          }
        } else {
          const result = await signInWithPopup(resolvedAuth, provider);
          credential = GoogleAuthProvider.credentialFromResult(result);
        }

        const token = credential?.accessToken ?? null;
        setAccessToken(token);
        return token;
      } catch {
        // ?좏겙 媛깆떊 ?ㅽ뙣 ??accessToken??null濡??ㅼ젙?섏뿬 ?댄썑 Drive ?몄텧???먯뿰?ㅻ읇寃??ㅽ뙣?섎룄濡?r
        setAccessToken(null);
        setError('Google Drive ?좏겙 媛깆떊 ?ㅽ뙣: ?щ줈洹몄씤???꾩슂?⑸땲??');
        return null;
      } finally {
        refreshPromiseRef.current = null;
      }
    };

    refreshPromiseRef.current = doRefresh();
    return refreshPromiseRef.current;
  }, []);

  const signOut = async () => {
    const resolvedAuth = await lazyFirebaseAuth();
    if (!resolvedAuth) return;
    setAccessToken(null);
    const API_KEY_STORAGE_KEYS = ['noa_api_key', 'noa_openai_key', 'noa_claude_key', 'noa_groq_key', 'noa_mistral_key'];
    API_KEY_STORAGE_KEYS.forEach(k => localStorage.removeItem(k));
    const { signOut: firebaseSignOut } = await import('firebase/auth');
    await firebaseSignOut(resolvedAuth);
  };

  const getIdToken = useCallback(async (): Promise<string | null> => {
    const resolvedAuth = await lazyFirebaseAuth();
    const u = resolvedAuth?.currentUser;
    if (!u) return null;
    return u.getIdToken();
  }, []);

  return (
    <AuthContext.Provider
      value={{
        user,
        userId: user?.uid ?? null,
        loading,
        signInWithGoogle,
        signOut,
        isConfigured,
        error,
        accessToken,
        refreshAccessToken,
        getIdToken,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  return useContext(AuthContext);
}

