function parseStepsFromResponse(raw: string): string[] {
  const trimmed = raw.trim();

  // JSON 諛곗뿴 吏곸젒 ?뚯떛 ?쒕룄
  try {
    const parsed = JSON.parse(trimmed);
    if (Array.isArray(parsed) && parsed.length > 0 && parsed.every(s => typeof s === 'string')) {
      return parsed.slice(0, 5);
